            // Check second part: p...q is strictly decreasing
            let dec = true;
            for (let i = p; i < q; i++) {
                if (nums[i] <= nums[i + 1]) {
                    dec = false;
                    break;
                }
            }
            if (!dec) continue;
            // Check third part: q...n-1 is strictly increasing
            let incEnd = true;
            for (let i = q; i < n - 1; i++) {
